      name: 'smoke',
      testMatch: '**/smoke/**/*.spec.js',
      use: { ...devices['Desktop Chrome'] },
    },
    {
      name: 'regression',
      testMatch: '**/regression/**/*.spec.js',
      use: { ...devices['Desktop Chrome'] },
    },
    {
      name: 'pwa',
      testMatch: '**/pwa/**/*.spec.js',
      use: { ...devices['Desktop Chrome'] },
    },
  ],
});

