// @ts-check
const { test, expect } = require('@playwright/test');

test.describe('Smoke — Hey Chill loads correctly', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto('/');
  });

  test('page title is "Hey Chill"', async ({ page }) => {
    await expect(page).toHaveTitle('Hey Chill');
  });

  test('header shows "Chill"', async ({ page }) => {
    await expect(page.locator('h1')).toHaveText('Chill');
  });

  test('mic button is visible and not disabled', async ({ page }) => {
    const micBtn = page.locator('#mic-btn');
    await expect(micBtn).toBeVisible();
    await expect(micBtn).not.toBeDisabled();
  });

  test('mic hint defaults to "Tap to speak"', async ({ page }) => {
    await expect(page.locator('#mic-hint')).toHaveText('Tap to speak');
  });

  test('settings button is visible', async ({ page }) => {
    await expect(page.locator('#settings-btn')).toBeVisible();
  });

  test('message area empty state is visible', async ({ page }) => {
    await expect(page.locator('#messages-empty')).toBeVisible();
  });

  test('transcript bar is initially hidden', async ({ page }) => {
    await expect(page.locator('#transcript-bar')).toBeHidden();
  });

  test('live transcript is initially hidden', async ({ page }) => {
