/**
 * Push-to-talk UI regression tests.
 *
 * The Web Speech API is not available in headless Chrome, so we inject a
 * mock SpeechRecognition before the page scripts run, allowing us to
 * test all UI state transitions without real audio.
 */
const { test, expect } = require('@playwright/test');

/**
 * Injects a controllable mock SpeechRecognition into the page context.
 * Returns helper functions to simulate recognition events.
 */
async function injectMockSpeechRecognition(page) {
  await page.addInitScript(() => {
    class MockSpeechRecognition extends EventTarget {
      constructor() {
        super();
        this.continuous = false;
        this.interimResults = false;
        this.lang = 'en-US';
        this.maxAlternatives = 1;
        window.__mockSR = this;
      }

      start() {
        this._started = true;
        if (this.onstart) this.onstart();
      }

      stop() {
        this._started = false;
        if (this.onend) this.onend();
      }

      /** Test helper — simulate a speech result */
      simulateResult(transcript, isFinal = false) {
        if (this.onresult) {
          const event = {
            resultIndex: 0,
            results: [
              Object.assign([{ transcript, confidence: 0.9 }], {
                isFinal,
                length: 1,
              }),
            ],
          };
          event.results.length = 1;
          this.onresult(event);
        }
      }

      /** Test helper — simulate recognition error */
      simulateError(error = 'network') {
        if (this.onerror) this.onerror({ error });
      }
    }

    window.SpeechRecognition = MockSpeechRecognition;
    window.webkitSpeechRecognition = MockSpeechRecognition;
  });
}

