    const micBtn = page.locator('#mic-btn');
    await micBtn.click();

    await expect(micBtn).toHaveAttribute('aria-pressed', 'true');
    await expect(micBtn).toHaveAttribute('aria-label', 'Stop recording');
  });

  test('mic hint changes to "Tap to stop" while recording', async ({ page }) => {
    await page.locator('#mic-btn').click();
    await expect(page.locator('#mic-hint')).toHaveText('Tap to stop');
  });

  test('live transcript area becomes visible when recording starts', async ({ page }) => {
    await page.locator('#mic-btn').click();
    await expect(page.locator('#live-transcript')).toBeVisible();
  });

