    await page.locator('#mic-btn').click();
    await expect(page.locator('#live-text')).toHaveText('Listening…');
  });

  test('clicking mic button again stops recording and returns to idle', async ({ page }) => {
    const micBtn = page.locator('#mic-btn');
    await micBtn.click();
    await micBtn.click();

    await expect(micBtn).toHaveAttribute('aria-pressed', 'false');
    await expect(micBtn).toHaveAttribute('aria-label', 'Start recording');
    await expect(page.locator('#mic-hint')).toHaveText('Tap to speak');
  });

  test('live transcript is hidden again after stopping', async ({ page }) => {
    const micBtn = page.locator('#mic-btn');
    await micBtn.click();
    await micBtn.click();
    await expect(page.locator('#live-transcript')).toBeHidden();
  });

  test('mic-ring element gets "recording" class while active', async ({ page }) => {
    await page.locator('#mic-btn').click();
    await expect(page.locator('#mic-ring')).toHaveClass(/recording/);
  });

  test('mic-btn element gets "recording" class while active', async ({ page }) => {
    await page.locator('#mic-btn').click();
    await expect(page.locator('#mic-btn')).toHaveClass(/recording/);
  });

  test('"recording" class is removed after stopping', async ({ page }) => {
    const micBtn = page.locator('#mic-btn');
    await micBtn.click();
    await micBtn.click();
    await expect(micBtn).not.toHaveClass(/recording/);
    await expect(page.locator('#mic-ring')).not.toHaveClass(/recording/);
  });
});

