/**
 * Transcription display regression tests.
 *
 * Covers: interim live text, final transcript capture, transcript bar actions.
 */
const { test, expect } = require('@playwright/test');

async function injectMockSpeechRecognition(page) {
  await page.addInitScript(() => {
    class MockSpeechRecognition {
      constructor() {
        this.continuous = true;
        this.interimResults = true;
        this.lang = 'en-US';
        this.maxAlternatives = 1;
        this._started = false;
        window.__mockSR = this;
      }

      start() {
        this._started = true;
        if (this.onstart) this.onstart();
      }

      stop() {
        const wasStarted = this._started;
        this._started = false;
        if (wasStarted && this.onend) this.onend();
      }

      simulateResult(transcript, isFinal) {
        if (!this.onresult) return;
        const resultArr = [{ transcript, confidence: 0.9 }];
        resultArr.isFinal = isFinal;
        this.onresult({
          resultIndex: 0,
          results: Object.assign([resultArr], { length: 1 }),
        });
      }
    }

    window.SpeechRecognition = MockSpeechRecognition;
    window.webkitSpeechRecognition = MockSpeechRecognition;
  });
}

test.describe('Transcription display', () => {
  test.beforeEach(async ({ page }) => {
    await injectMockSpeechRecognition(page);
    await page.goto('/');
    // Start recording
    await page.locator('#mic-btn').click();
  });

  test('interim speech result updates live text', async ({ page }) => {
    await page.evaluate(() => window.__mockSR.simulateResult('hello', false));
    await expect(page.locator('#live-text')).toHaveText('hello');
  });

  test('live text shows interim + final combined text', async ({ page }) => {
    await page.evaluate(() => {
      window.__mockSR.simulateResult('hello ', true);   // final
      window.__mockSR.simulateResult('world', false);   // interim
    });
    await expect(page.locator('#live-text')).toContainText('world');
  });

  test('live text has "has-text" class when non-empty', async ({ page }) => {
    await page.evaluate(() => window.__mockSR.simulateResult('test', false));
    await expect(page.locator('#live-text')).toHaveClass(/has-text/);
  });

  test('final transcript appears in transcript bar after stop', async ({ page }) => {
    await page.evaluate(() => window.__mockSR.simulateResult('send this message', true));
    // Stop recording (simulates VAD or manual stop)
    await page.evaluate(() => window.__mockSR.stop());

    await expect(page.locator('#transcript-bar')).toBeVisible();
    await expect(page.locator('#transcript-text')).toHaveText('send this message');
  });

  test('transcript bar is hidden if no speech was captured', async ({ page }) => {
    // Stop without any final transcript
    await page.evaluate(() => window.__mockSR.stop());
    await expect(page.locator('#transcript-bar')).toBeHidden();
  });

  test('discard button hides the transcript bar', async ({ page }) => {
    await page.evaluate(() => {
      window.__mockSR.simulateResult('discard me', true);
      window.__mockSR.stop();
    });
    await expect(page.locator('#transcript-bar')).toBeVisible();
    await page.locator('#discard-btn').click();
    await expect(page.locator('#transcript-bar')).toBeHidden();
  });

  test('send button hides transcript bar and adds message to history', async ({ page }) => {
    await page.evaluate(() => {
      window.__mockSR.simulateResult('message to send', true);
      window.__mockSR.stop();
    });
    await expect(page.locator('#transcript-bar')).toBeVisible();

    await page.locator('#send-btn').click();

    await expect(page.locator('#transcript-bar')).toBeHidden();
    await expect(page.locator('.message')).toBeVisible();
    await expect(page.locator('.message-text')).toHaveText('message to send');
  });

  test('empty state is hidden after a message is added', async ({ page }) => {
    await page.evaluate(() => {
      window.__mockSR.simulateResult('anything', true);
      window.__mockSR.stop();
    });
    await page.locator('#send-btn').click();
    await expect(page.locator('#messages-empty')).toBeHidden();
  });
});

