// @ts-check
/**
 * Slack webhook integration regression tests.
 *
 * Uses Playwright's network interception (route) to catch fetch calls
 * rather than hitting a real webhook endpoint.
 */
const { test, expect } = require('@playwright/test');

const MOCK_WEBHOOK_URL = 'https://example.com/webhook/hey-chill';

async function injectMockSpeechRecognition(page) {
  await page.addInitScript(() => {
    class MockSpeechRecognition {
      constructor() {
        this.continuous = true;
        this.interimResults = true;
        window.__mockSR = this;
      }
      start() { if (this.onstart) this.onstart(); }
      stop() { if (this.onend) this.onend(); }
      simulateResult(transcript, isFinal) {
        if (!this.onresult) return;
        const resultArr = [{ transcript, confidence: 0.9 }];
        resultArr.isFinal = isFinal;
        this.onresult({ resultIndex: 0, results: Object.assign([resultArr], { length: 1 }) });
      }
    }
    window.SpeechRecognition = MockSpeechRecognition;
    window.webkitSpeechRecognition = MockSpeechRecognition;
  });
}

async function setWebhookUrl(page, url) {
  await page.locator('#settings-btn').click();
  await page.locator('#webhook-url').fill(url);
  await page.locator('#save-settings').click();
}

async function speakAndSend(page, text) {
  await page.locator('#mic-btn').click();
  await page.evaluate((t) => {
    window.__mockSR.simulateResult(t, true);
    window.__mockSR.stop();
  }, text);
  await expect(page.locator('#transcript-bar')).toBeVisible();
  await page.locator('#send-btn').click();
}

test.describe('Webhook integration', () => {
  test.beforeEach(async ({ page }) => {
    await injectMockSpeechRecognition(page);
    await page.goto('/');
  });

  test('POST is made to the configured webhook URL', async ({ page }) => {
    let interceptedRequest = null;

    await page.route(MOCK_WEBHOOK_URL, (route) => {
      interceptedRequest = route.request();
      route.fulfill({ status: 200, body: 'ok' });
    });

    await setWebhookUrl(page, MOCK_WEBHOOK_URL);
    await speakAndSend(page, 'hello chill');

    expect(interceptedRequest).not.toBeNull();
    expect(interceptedRequest.method()).toBe('POST');
  });

  test('POST body contains correct payload shape', async ({ page }) => {
    let body = null;

    await page.route(MOCK_WEBHOOK_URL, async (route) => {
      body = route.request().postDataJSON();
      await route.fulfill({ status: 200, body: 'ok' });
    });

    await setWebhookUrl(page, MOCK_WEBHOOK_URL);
    await speakAndSend(page, 'test payload');

    expect(body).toMatchObject({
      text: 'test payload',
      source: 'hey-chill',
    });
    expect(typeof body.timestamp).toBe('string');
    // timestamp should be a valid ISO 8601 date
    expect(() => new Date(body.timestamp)).not.toThrow();
  });

  test('Content-Type header is application/json', async ({ page }) => {
    let contentType = null;

    await page.route(MOCK_WEBHOOK_URL, async (route) => {
      contentType = route.request().headers()['content-type'];
      await route.fulfill({ status: 200, body: 'ok' });
    });

    await setWebhookUrl(page, MOCK_WEBHOOK_URL);
    await speakAndSend(page, 'json check');

    expect(contentType).toContain('application/json');
  });

  test('message status shows "Sent" after successful webhook response', async ({ page }) => {
    await page.route(MOCK_WEBHOOK_URL, (route) =>
      route.fulfill({ status: 200, body: 'ok' })
    );

    await setWebhookUrl(page, MOCK_WEBHOOK_URL);
    await speakAndSend(page, 'success case');

    await expect(page.locator('.message-status')).toHaveText('Sent', { timeout: 5000 });
  });

  test('message status shows "Failed" when webhook returns 500', async ({ page }) => {
    await page.route(MOCK_WEBHOOK_URL, (route) =>
      route.fulfill({ status: 500, body: 'Server Error' })
    );

    await setWebhookUrl(page, MOCK_WEBHOOK_URL);
    await speakAndSend(page, 'error case');

    await expect(page.locator('.message-status')).toHaveText('Failed', { timeout: 5000 });
  });

  test('message status shows "No webhook set" when no URL configured', async ({ page }) => {
    // Ensure no webhook URL in localStorage
    await page.evaluate(() => localStorage.removeItem('webhookUrl'));

    await speakAndSend(page, 'no webhook');

    await expect(page.locator('.message-status')).toHaveText('No webhook set', { timeout: 5000 });
  });

  test('webhook URL is persisted in localStorage', async ({ page }) => {
    await setWebhookUrl(page, MOCK_WEBHOOK_URL);

    const stored = await page.evaluate(() => localStorage.getItem('webhookUrl'));
    expect(stored).toBe(MOCK_WEBHOOK_URL);
  });

  test('HTML in message text is escaped (XSS prevention)', async ({ page }) => {
    await page.route(MOCK_WEBHOOK_URL, (route) =>
      route.fulfill({ status: 200, body: 'ok' })
    );
    await setWebhookUrl(page, MOCK_WEBHOOK_URL);
    await speakAndSend(page, '<script>alert(1)</script>');

    // The message-text should contain the escaped literal, not execute the script
    const msgHtml = await page.locator('.message-text').innerHTML();
    expect(msgHtml).not.toContain('<script>');
    expect(msgHtml).toContain('&lt;script&gt;');
  });
});

