// @ts-check
/**
 * Settings modal regression tests.
 */
const { test, expect } = require('@playwright/test');

test.describe('Settings modal', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto('/');
  });

  test('settings modal is hidden on page load', async ({ page }) => {
    await expect(page.locator('#modal-overlay')).toBeHidden();
  });

  test('clicking settings button opens the modal', async ({ page }) => {
    await page.locator('#settings-btn').click();
    await expect(page.locator('#modal-overlay')).toBeVisible();
  });

  test('modal contains webhook URL input', async ({ page }) => {
    await page.locator('#settings-btn').click();
    await expect(page.locator('#webhook-url')).toBeVisible();
  });

  test('webhook input is focused when modal opens', async ({ page }) => {
    await page.locator('#settings-btn').click();
    await expect(page.locator('#webhook-url')).toBeFocused();
  });

  test('close button (X) dismisses the modal', async ({ page }) => {
    await page.locator('#settings-btn').click();
    await page.locator('#modal-close').click();
    await expect(page.locator('#modal-overlay')).toBeHidden();
  });

  test('clicking overlay backdrop dismisses the modal', async ({ page }) => {
    await page.locator('#settings-btn').click();
    // Click the overlay area outside the modal dialog
    await page.locator('#modal-overlay').click({ position: { x: 5, y: 5 } });
    await expect(page.locator('#modal-overlay')).toBeHidden();
  });

  test('pressing Escape dismisses the modal', async ({ page }) => {
    await page.locator('#settings-btn').click();
    await page.keyboard.press('Escape');
    await expect(page.locator('#modal-overlay')).toBeHidden();
  });

  test('Save button saves webhook URL and closes modal', async ({ page }) => {
    const url = 'https://n8n.example.com/webhook/hey-chill';

    await page.locator('#settings-btn').click();
    await page.locator('#webhook-url').fill(url);
    await page.locator('#save-settings').click();

    await expect(page.locator('#modal-overlay')).toBeHidden();

    const stored = await page.evaluate(() => localStorage.getItem('webhookUrl'));
    expect(stored).toBe(url);
  });

  test('modal pre-fills existing webhook URL when reopened', async ({ page }) => {
    const url = 'https://n8n.example.com/webhook/hey-chill';

    // Save a URL
    await page.locator('#settings-btn').click();
    await page.locator('#webhook-url').fill(url);
    await page.locator('#save-settings').click();

    // Reopen
    await page.locator('#settings-btn').click();
    await expect(page.locator('#webhook-url')).toHaveValue(url);
  });

  test('modal has correct ARIA attributes', async ({ page }) => {
    await page.locator('#settings-btn').click();
    const modal = page.locator('[role="dialog"]');
    await expect(modal).toHaveAttribute('aria-modal', 'true');
    await expect(modal).toHaveAttribute('aria-labelledby', 'modal-title');
  });
});

