// @ts-check
/**
 * PWA regression tests.
 *
 * Covers: web app manifest, service worker registration, installability criteria.
 */
const { test, expect } = require('@playwright/test');

test.describe('PWA — manifest', () => {
  test('manifest.json is reachable and returns 200', async ({ request }) => {
    const res = await request.get('/manifest.json');
    expect(res.status()).toBe(200);
  });

  test('manifest has required "name" field', async ({ request }) => {
    const manifest = await (await request.get('/manifest.json')).json();
    expect(typeof manifest.name).toBe('string');
    expect(manifest.name.length).toBeGreaterThan(0);
  });

  test('manifest name is "Hey Chill"', async ({ request }) => {
    const manifest = await (await request.get('/manifest.json')).json();
    expect(manifest.name).toBe('Hey Chill');
  });

  test('manifest has required "start_url" field', async ({ request }) => {
    const manifest = await (await request.get('/manifest.json')).json();
    expect(manifest.start_url).toBeTruthy();
  });

  test('manifest display is "standalone" (enables PWA install)', async ({ request }) => {
    const manifest = await (await request.get('/manifest.json')).json();
    expect(manifest.display).toBe('standalone');
  });

  test('manifest has at least one icon with src and sizes', async ({ request }) => {
    const manifest = await (await request.get('/manifest.json')).json();
    expect(Array.isArray(manifest.icons)).toBe(true);
    expect(manifest.icons.length).toBeGreaterThan(0);
    for (const icon of manifest.icons) {
      expect(icon.src).toBeTruthy();
      expect(icon.sizes).toBeTruthy();
    }
  });

  test('manifest icons are reachable', async ({ request }) => {
    const manifest = await (await request.get('/manifest.json')).json();
    for (const icon of manifest.icons) {
      const res = await request.get(icon.src);
      expect(res.status()).toBeLessThan(400);
    }
  });

  test('manifest has background_color and theme_color', async ({ request }) => {
    const manifest = await (await request.get('/manifest.json')).json();
    expect(manifest.background_color).toMatch(/^#[0-9a-fA-F]{3,8}$/);
    expect(manifest.theme_color).toMatch(/^#[0-9a-fA-F]{3,8}$/);
  });

  test('page has <link rel="manifest"> pointing to manifest.json', async ({ page }) => {
    await page.goto('/');
    const href = await page.locator('link[rel="manifest"]').getAttribute('href');
    expect(href).toBeTruthy();
    expect(href).toContain('manifest');
  });
});

test.describe('PWA — service worker', () => {
  test('sw.js is reachable and returns 200', async ({ request }) => {
    const res = await request.get('/sw.js');
    expect(res.status()).toBe(200);
  });

  test('browser API for service worker is available', async ({ page }) => {
    await page.goto('/');
    const hasSW = await page.evaluate(() => 'serviceWorker' in navigator);
    expect(hasSW).toBe(true);
  });

  test('service worker registers and becomes active', async ({ page }) => {
    await page.goto('/');

    // Wait up to 10 s for SW to become active
    const isActive = await page.evaluate(async () => {
      if (!('serviceWorker' in navigator)) return false;
      const reg = await navigator.serviceWorker.ready;
      return !!reg.active;
    });

    expect(isActive).toBe(true);
  });

  test('service worker scope covers the root path', async ({ page }) => {
    await page.goto('/');
    const scope = await page.evaluate(async () => {
      const reg = await navigator.serviceWorker.ready;
      return reg.scope;
    });
    // Scope should be the origin root
    expect(new URL(scope).pathname).toBe('/');
  });
});

test.describe('PWA — installability criteria', () => {
  test('page is served over HTTPS', async ({ page }) => {
    await page.goto('/');
    const protocol = await page.evaluate(() => location.protocol);
    expect(protocol).toBe('https:');
  });

  test('page has <meta name="viewport"> for mobile-friendliness', async ({ page }) => {
    await page.goto('/');
    const viewport = await page.locator('meta[name="viewport"]').getAttribute('content');
    expect(viewport).toBeTruthy();
  });

  test('page has apple-mobile-web-app-capable meta tag', async ({ page }) => {
    await page.goto('/');
    const val = await page.locator('meta[name="apple-mobile-web-app-capable"]').getAttribute('content');
    expect(val).toBe('yes');
  });
});

