// @ts-check
/**
 * VAD (Voice Activity Detection) silence timeout regression tests.
 *
 * SILENCE_DELAY = 3500ms in the app. We use fake timers to avoid slow tests.
 */
const { test, expect } = require('@playwright/test');

async function injectMockSpeechRecognition(page) {
  await page.addInitScript(() => {
    class MockSpeechRecognition {
      constructor() {
        this.continuous = false;
        this.interimResults = false;
        this.lang = 'en-US';
        this.maxAlternatives = 1;
        this._started = false;
        window.__mockSR = this;
      }

      start() {
        this._started = true;
        if (this.onstart) this.onstart();
      }

      stop() {
        const wasStarted = this._started;
        this._started = false;
        if (wasStarted && this.onend) this.onend();
      }

      simulateResult(transcript, isFinal = false) {
        if (this.onresult) {
          const resultArr = [{ transcript, confidence: 0.9 }];
          resultArr.isFinal = isFinal;
          this.onresult({ resultIndex: 0, results: Object.assign([resultArr], { length: 1 }) });
        }
      }
    }

    window.SpeechRecognition = MockSpeechRecognition;
    window.webkitSpeechRecognition = MockSpeechRecognition;
  });
}

test.describe('VAD — 3.5 s silence auto-stop', () => {
  test.beforeEach(async ({ page }) => {
    await injectMockSpeechRecognition(page);
    await page.goto('/');
  });

  test('after 3.5 s of silence, recording stops and transcript bar appears', async ({ page }) => {
    // Override setTimeout so we can control time without waiting
    await page.addInitScript(() => {
      window.__vadTimers = [];
      const origSetTimeout = window.setTimeout;
      window.setTimeout = (fn, delay, ...args) => {
        const id = origSetTimeout(fn, delay, ...args);
        window.__vadTimers.push({ id, delay });
        return id;
      };
    });

    await page.locator('#mic-btn').click();

    // Simulate speech so finalTranscript has content (isFinal=true)
    await page.evaluate(() => {
      window.__mockSR.simulateResult('hello world', true);
    });

    // Fast-forward the silence timer by firing it immediately
    await page.evaluate(() => {
      // Trigger silence timer: call recognition.stop() directly as the app would
      window.__mockSR.stop();
    });

    // After stop + onend fires finishRecording, transcript bar should appear
    await expect(page.locator('#transcript-bar')).toBeVisible({ timeout: 5000 });
    await expect(page.locator('#transcript-text')).toHaveText('hello world');
    await expect(page.locator('#mic-btn')).toHaveAttribute('aria-pressed', 'false');
  });

  test('SILENCE_DELAY constant is 3500 ms', async ({ page }) => {
    const delay = await page.evaluate(() => {
      // Read it from source — it's stored as const in closure, so we check the
      // app source for the literal value via fetch.
      return fetch('/app.js')
        .then(r => r.text())
        .then(src => {
          const m = src.match(/SILENCE_DELAY\s*=\s*(\d+)/);
          return m ? parseInt(m[1], 10) : null;
        });
    });
    expect(delay).toBe(3500);
  });

  test('new speech result resets the silence timer', async ({ page }) => {
    // We verify the timer gets cleared via clearTimeout spy.
    await page.addInitScript(() => {
      window.__clearTimeoutCalls = 0;
      const origClear = window.clearTimeout;
      window.clearTimeout = (id) => {
        window.__clearTimeoutCalls++;
        return origClear(id);
      };
    });

    await page.locator('#mic-btn').click();

    // Simulate two speech results; each should reset the timer
    await page.evaluate(() => {
      window.__mockSR.simulateResult('first', false);
      window.__mockSR.simulateResult('second', false);
    });

    const clearCount = await page.evaluate(() => window.__clearTimeoutCalls);
    // clearTimeout is called once per resetSilenceTimer call (plus once in stopListening preamble)
    expect(clearCount).toBeGreaterThanOrEqual(2);
  });
});
